import * as React from 'react';
import { useStaticQuery, graphql } from 'gatsby';
import loadable from '@loadable/component';
import Box from '@mui/material/Box';
import Layout from '../components/layout';
import { Seo } from '../components/seo';

const SectionMenu = loadable(() => import('../components/sections/menu'));
const Mainvisual = loadable(() => import('../components/mainvisual'));

const IndexPage = () => {
  const data = useStaticQuery(graphql`
    {
      allFile(
        sort: { relativePath: ASC }
        filter: { relativeDirectory: { eq: "mainvisuals" } }
      ) {
        edges {
          node {
            relativeDirectory
            relativePath
            childImageSharp {
              gatsbyImageData(width: 1920)
            }
          }
        }
      }
    }
  `);

  const duration = 1500;
  const delay = 250;

  const [isLoaded, setIsLoaded] = React.useState(false);
  const [isEnded, setIsEnded] = React.useState(false);

  const onLoad = () => {
    setIsLoaded(true);
    setTimeout(() => {
      setIsEnded(true);
    }, duration + delay);
  };

  React.useEffect(() => {
    document.readyState === 'complete'
      ? onLoad()
      : window.addEventListener('load', onLoad);
  }, []);

  return (
    <Layout>
      {!isEnded && (
        <Box
          sx={{
            position: 'fixed',
            top: 0,
            left: 0,
            width: '100%',
            height: '100vh',
            backgroundColor: '#eee',
            transition: `opacity ${duration}ms ease-out ${delay}ms`,
            opacity: isLoaded ? 0 : 1,
            pointerEvents: 'none',
            zIndex: 2000
          }}
        />
      )}
      <SectionMenu />
      <Mainvisual images={data} />
    </Layout>
  );
};

export default IndexPage;

export const Head = () => {
  return <Seo />;
};
